#include<cstdio>
#include<queue>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();bool flag=false;while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return flag ? -res : res ;
}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=5e5+10;int n,p,s[N],P[N],L,R,K,c[N],ql[N],qr[N];long long ans;
struct PP{int p,v;inline bool operator < (const PP&x)const{return v<x.v;};};
std::priority_queue<PP> h;struct Seg{int l,r,sz;}t[N<<5];int Rt[N],cnt;
inline void add(int cur,int &x,int pos,int l=1,int r=p)
{
//	printf("add %d %d %d\n",pos,l,r);
	t[x=++cnt]=t[cur];if(l==r){++t[x].sz;return;} int mid=(l+r)>>1;
	pos<=mid?add(t[cur].l,t[x].l,pos,l,mid):add(t[cur].r,t[x].r,pos,mid+1,r);
	t[x].sz=t[t[x].l].sz+t[t[x].r].sz;
}
inline int qry(int cl,int cr,int k,int l=1,int r=p)
{
	if(l==r)return P[l];int lsz=t[t[cr].l].sz-t[t[cl].l].sz;int mid=(l+r)>>1;
	if(lsz>=k)return qry(t[cl].l,t[cr].l,k,l,mid);return qry(t[cl].r,t[cr].r,k-lsz,mid+1,r);
}
inline int bnd(int k){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
int main()
{
	n=read()+1;K=read();L=read();R=read();rep(2,n,i)P[i]=s[i]=s[i-1]+read();P[1]=0;
	p=n;std::sort(P+1,P+p+1);p=std::unique(P+1,P+p+1)-P-1;
	rep(1,n,i){add(Rt[i-1],Rt[i],bnd(s[i]));qr[i]=max(1,i-L);ql[i]=max(1,i-R);}
	rep(1,n,i)if(i-L>0)h.push((PP){i,s[i]-qry(Rt[ql[i]-1],Rt[qr[i]],c[i]=1)});
	
	while(!h.empty()&&K--)
	{
		ans+=h.top().v;int i=h.top().p;h.pop();
		if((++c[i])<=qr[i]-ql[i]+1)h.push((PP){i,s[i]-qry(Rt[ql[i]-1],Rt[qr[i]],c[i])});
	}
	printf("%lld\n",ans);return 0;
}
